import { ColoredChartDimension } from './categorical-bar-chart-data.js';
import { Point } from '../../core/types/point.js';

export interface CategoricalBarChartMousePositionState {
  relative: Point;
  absolute: Point;
}

export interface CategoricalBarChartOverlayState {
  pinnedTooltip: boolean;
  visibleTooltip: boolean;
  mouseInBounds: boolean;
  mousePosition?: CategoricalBarChartMousePositionState;
}

export interface CategoricalBarChartState {
  filteredDimensions: Set<string>;
  highlightedDimension: ColoredChartDimension | undefined;
  overlays: CategoricalBarChartOverlayState;
  hoveredThresholdId: string | undefined;
}

export const defaultOverlayValue: CategoricalBarChartOverlayState = {
  pinnedTooltip: false,
  visibleTooltip: false,
  mouseInBounds: false,
};

export const initialState: CategoricalBarChartState = {
  filteredDimensions: new Set(),
  highlightedDimension: undefined,
  overlays: defaultOverlayValue,
  hoveredThresholdId: undefined,
};
